try {
  const url = `https://news.google.com/rss/search?q=${encodeURIComponent(query.topic)}&hl=en-US&gl=US&ceid=US:en`;
  const response = await this.helpers.httpRequest({ method: 'GET', url: url });
  const items = response.match(/<item>([\s\S]*?)<\/item>/g) || [];
  const results = items.slice(0, 15).map(item => {
    const title = item.match(/<title>([\s\S]*?)<\/title>/)?.[1] || 'No title';
    const link = item.match(/<link>([\s\S]*?)<\/link>/)?.[1] || 'No link';
    const pubDate = item.match(/<pubDate>([\s\S]*?)<\/pubDate>/)?.[1] || 'No date';
    return { title: title.replace(/<!\[CDATA\[(.*?)\]\]>/, '$1'), link, pubDate };
  });
  return JSON.stringify(results);
} catch (err) {
  return 'Error fetching news: ' + err.message;
}

try {
  const response = await this.helpers.httpRequest({ method: 'GET', url: query.url });
  const text = response.replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '').replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').substring(0, 30000);
  return text;
} catch (err) {
  return 'Failed to scrape URL: ' + err.message;
}
